#include<bits/stdc++.h>
using namespace std;
long long ans=0;
const int N=500005;
int fa[N][25],deep[N],t;
struct edge
{
    int from,to,next;
} a[2*N];
int num[2*N],tot=0;
void add(int x,int y)
{
    a[++tot].from=x;
	a[tot].to=y;
	a[tot].next=num[x];
	num[x]=tot;
}
int lca(int x,int y)
{
	if(deep[x]<deep[y]) swap(x,y);
	while(deep[x]>deep[y]) x=fa[x][(int)log2(deep[x]-deep[y])];
	if(x==y) return x;
	for(int k=log2(deep[x]);k>=0;k--)
	{
	    if(fa[x][k]!=fa[y][k])
	    {
	    	x=fa[x][k];
			y=fa[y][k];
	    }
	}
    return fa[x][0];
}
void dfs(int x,int f)				
{
	deep[x]=deep[f]+1;
	fa[x][0]=f;
	for(int i=1;(1<<i)<=deep[x];i++)
	{
		fa[x][i]=fa[fa[x][i-1]][i-1];
	}
	for(int i=num[x];i;i=a[i].next)
	{
        if(a[i].to!=f) dfs(a[i].to,x);
    }
}
int n,m,x,y,z;
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
    cin>>n>>m;
    for(int i=1;i<n;i++)
    {
        cin>>x>>y;
        add(x,y);
        add(y,x);
    }
    dfs(1,0);
    while(m--)
    {
        cin>>x>>y>>z;
        int t1=lca(x,y),t2=lca(y,z),t3=lca(x,z);
        if(t1==t2) t=t3;
        else if(t1==t3) t=t2;
        else t=t1;
        ans=deep[x]+deep[y]+deep[z]-(deep[t1]+deep[t2]+deep[t3]);
        cout<<t<<" "<<ans<<'\n';
    }
    return 0;
}
